INSERT INTO public.house_types (id, type_name, bedrooms, bathrooms, sqft, description, photo_url) VALUES (1, 'Mobile Home', 3, 2.5, 900, 'Самый бюджетный вариант. 3 спальни, 2.5 ванны. Построен между 1940 и 1980.', NULL);
INSERT INTO public.house_types (id, type_name, bedrooms, bathrooms, sqft, description, photo_url) VALUES (2, '90''s 2-Story House', 3, 2.5, 1600, 'Двухэтажный дом среднего класса. 3 спальни, 2.5 ванны. Бильярд на втором этаже. 1987–2010.', NULL);
INSERT INTO public.house_types (id, type_name, bedrooms, bathrooms, sqft, description, photo_url) VALUES (3, 'Average Suburban House', 3, 2.5, 1400, 'Стандартный пригородный дом. 3 спальни, 2.5 ванны, 5 шкафов. 1956–1982.', NULL);
INSERT INTO public.house_types (id, type_name, bedrooms, bathrooms, sqft, description, photo_url) VALUES (4, 'Modern Average Suburban House', 3, 2.5, 1700, 'Современный пригородный дом на 3 спальни, 2.5 ванны. Гараж на 3 машины. 1988–2003.', NULL);
INSERT INTO public.house_types (id, type_name, bedrooms, bathrooms, sqft, description, photo_url) VALUES (5, 'Upper-Class 90''s Bungalow', 2, 1.5, 1100, 'Небольшое бунгало. 2 спальни, 1.5 ванны. 1989–1998.', NULL);
INSERT INTO public.house_types (id, type_name, bedrooms, bathrooms, sqft, description, photo_url) VALUES (6, 'Average 2-Story House', 4, 3.5, 2200, 'Двухэтажный дом в фермерском стиле. 4 спальни, 3.5 ванны. 1975–1995.', NULL);
INSERT INTO public.house_types (id, type_name, bedrooms, bathrooms, sqft, description, photo_url) VALUES (7, 'Mansion #1', 5, 3.5, 4000, 'Особняк! 5 спален, 3.5 ванны. 2 гостиные, 2 столовые, огромная кухня. 1990–наши дни.', NULL);
INSERT INTO public.house_types (id, type_name, bedrooms, bathrooms, sqft, description, photo_url) VALUES (8, 'Old Farmhouse', 4, 2.5, 2500, 'Старый фермерский дом с камином, верандой, кабинетом и гаражом. 1890–1945.', NULL);
INSERT INTO public.house_types (id, type_name, bedrooms, bathrooms, sqft, description, photo_url) VALUES (9, 'Lakeside Lodge', 4, 3.5, 3800, 'Дом на озере с пирсом и балконами. Цокольный этаж с бильярдом. 2005–наши дни.', NULL);
INSERT INTO public.house_types (id, type_name, bedrooms, bathrooms, sqft, description, photo_url) VALUES (10, 'Average 2-Story Suburban House', 3, 3.0, 1800, 'Пригородный двухэтажный дом. 3 спальни, 3 ванны. 1965–1980.', NULL);
INSERT INTO public.house_types (id, type_name, bedrooms, bathrooms, sqft, description, photo_url) VALUES (11, 'Old Suburban House', 4, 4.0, 2000, 'Старый пригородный дом. 4 спальни, 4 ванны. 1920–1959.', NULL);
INSERT INTO public.house_types (id, type_name, bedrooms, bathrooms, sqft, description, photo_url) VALUES (12, 'Original 2-Story Suburban House', 3, 3.0, 1800, 'Редчайший дом! Оригинал из бета-версии Greenville. 1982.', NULL);
INSERT INTO public.house_types (id, type_name, bedrooms, bathrooms, sqft, description, photo_url) VALUES (13, 'Average 2-Story Suburban House #3', 3, 2.5, 1700, 'Пригородный двухэтажный дом с гостиной, прачечной и гаражом. 1960–1980.', NULL);
INSERT INTO public.house_types (id, type_name, bedrooms, bathrooms, sqft, description, photo_url) VALUES (14, 'Mansion #2', 4, 3.5, 4200, 'Второй особняк. 4 спальни, 3.5 ванны. Бильярд, фойе, гардеробная. 1990–наши дни.', NULL);
INSERT INTO public.house_types (id, type_name, bedrooms, bathrooms, sqft, description, photo_url) VALUES (15, 'Large 2-Story Suburban House', 3, 3.0, 2400, 'Большой двухэтажный пригородный дом. 3 спальни, 3 ванны. 1980–2010.', NULL);
INSERT INTO public.house_types (id, type_name, bedrooms, bathrooms, sqft, description, photo_url) VALUES (16, 'Average Suburban House', 5, 3.0, 2300, 'Просторный пригородный дом. 5 спален, 3 ванны. 1990–наши дни.', NULL);
INSERT INTO public.house_types (id, type_name, bedrooms, bathrooms, sqft, description, photo_url) VALUES (17, 'Mobile Home', 1, 1.0, 500, 'Маленький мобильный дом на одну спальню. Самый дешёвый вариант. 2005–наши дни.', NULL);
INSERT INTO public.house_types (id, type_name, bedrooms, bathrooms, sqft, description, photo_url) VALUES (18, 'Modern Triangle House', 3, 2.0, 1600, 'Современный треугольный дом. 3 спальни, 2 ванны. 2015–наши дни.', NULL);
INSERT INTO public.house_types (id, type_name, bedrooms, bathrooms, sqft, description, photo_url) VALUES (19, 'Modern House', 3, 2.0, 1500, 'Современный дом в минималистичном стиле.', NULL);
