INSERT INTO public.house_types (id, type_name, bedrooms, bathrooms, sqft, description, photo_url) VALUES (23, 'Cozy Rustic Suburban House', 3, 3.0, 2000, 'Уютный деревенский пригородный дом. 3 спальни, 3 ванны. v1.62.0.', NULL);
INSERT INTO public.house_types (id, type_name, bedrooms, bathrooms, sqft, description, photo_url) VALUES (24, 'Average Suburban Family House', 4, 3.0, 2200, 'Средний семейный дом. 4 спальни, 3 ванны. v1.62.0.', NULL);
